ht: calc(100% + 2px);\n          top: 50%;\n          transform: translateY(-50%);\n          filter: var(--utel-widget-icon-filter-blue);\n          opacity: 0;\n          transition: opacity 0.125s ease;\n        }\n        &:hover {\n          img {\n            opacity: 1;\n          }\n        }\n      }\n\n      .without-the-call-action {\n        display: flex;\n        align-items: center;\n        justify-content: center;\n      }\n\n      &:nth-child(2) {\n        min-width: 180px;\n      }\n      &:nth-child(3) {\n        text-align: center;\n        min-width: 28ch;\n      }\n      &:nth-child(4) {\n        text-align: center;\n        min-width: 140px;\n      }\n      &:nth-child(5) {\n        text-align: center;\n        min-width: 160px;\n      }\n      &:nth-child(6) {\n        text-align: left;\n        min-width: 160px;\n      }\n    }\n  }\n\n  .calls-table-header {\n    width: auto !important;\n    height: 46px;\n    background: var(--utel-widget-bg-012);\n    font-weight: 600;\n    align-items: center;\n    box-shadow: 0 4px 10px rgba($color: #000000, $alpha: 0.1);\n    min-width: 1200px;\n  }\n\n  .calls-table-body {\n    width: auto !important;\n    height: calc(100vh - 66px - 42px - 46px - 66px);\n    overflow-y: auto;\n    overflow-x: hidden;\n    min-width: 1200px;\n\n    position: relative;\n    .calls {\n      position: relative;\n      div.raw {\n        width: 100%;\n        top: var(--from-top);\n        &:nth-child(even) {\n          background-color: var(--utel-widget-bg-011);\n        }\n        span {\n          height: 20px;\n          &:first-child {\n            display: flex;\n            align-items: center;\n            .status-bar {\n              height: 40px;\n              width: 4px;\n              margin-right: 8px;\n              background-color: var(--utel-widget-icon-filter);\n              opacity: 0.5;\n            }\n            img {\n              height: 20px;\n              filter: invert(100%);\n            }\n          }\n        }\n        &.incoming {\n          span:first-child img {\n            filter: var(--utel-widget-icon-filter-green);\n          }\n        }\n        &.outgoing {\n          span:first-child img {\n            filter: var(--utel-widget-icon-filter-blue);\n          }\n        }\n        &.missed {\n          span:first-child .status-bar {\n            background-color: var(--utel-red);\n          }\n          span:first-child img {\n            filter: var(--utel-widget-icon-filter-red);\n          }\n        }\n      }\n    }\n  }\n}\n\n.calls-table-rows-move,\n.calls-table-rows-enter-active,\n.calls-table-rows-leave-active {\n  transition: all 0.25s cubic-bezier(0.165, 0.84, 0.44, 1);\n}\n\n.calls-table-rows-enter-from {\n  opacity: 0;\n  transform: translate(0, 30px);\n}\n.calls-table-rows-leave-to {\n  opacity: 0;\n}\n\n/* ensure leaving items are taken out of layout flow so that moving\n   animations can be calculated correctly. */\n.calls-table-rows-leave-active {\n  position: absolute;\n}\n"],"sourceRoot":""}]);
